package hw01.shape;

import java.awt.Color;
import java.awt.Graphics;

/**
 * 
 * @author charlielockyer
 * An concrete class describing a composite shape on a 2D plane, like a screen
 * A composite shape is composed of two other shapes and delegates its painting instructions to
 * those shapes.
 * Composite shapes can be composed to an arbitrary degree and do not inherently have color
 */
public class CompositeShape extends AShape {

	/**
	 * One component shape of the CompositeShape
	 */
	private AShape shape1;

	/**
	 * The other component shape of the CompositeShape
	 */
	private AShape shape2;

	/**
	 * Constructs a CompositeShape object
	 * @param shape1 the first component shape of the CompositeShape
	 * @param shape2 the other component shape of the CompositeShape
	 */
	public CompositeShape(AShape shape1, AShape shape2) {
		this.shape1 = shape1;
		this.shape2 = shape2;
		this.setXPos(Math.min(shape1.getXPos(), shape2.getXPos()));
		this.setYPos(Math.min(shape1.getYPos(), shape2.getYPos()));
	}

	/**
	 * Sets the color of the shape to an input color defined by the Color class by delegating
	 * to the component shapes
	 * @param color the color of the shape
	 */
	public void setColor(Color color) {
		shape1.setColor(color);
		shape2.setColor(color);
	}

	/**
	 * Paints the shape on the screen, abstract because each different shape is painted differently
	 * @param g the graphics object on which the shape will be painted
	 */
	public void paint(Graphics g) {
		shape1.paint(g);
		shape2.paint(g);
	}
}

package hw01.shape;

import java.awt.Color;
import java.awt.Graphics;

/**
 * 
 * @author charlielockyer
 * A concrete class representing an ellipse that can be painted on a graphics object
 */
public class Ellipse extends ASimpleShape {

	/**
	 * The width of the ellipse
	 */
	private int width;

	/**
	 * The height of the ellipse
	 */
	private int height;

	/**
	 * Constructs an ellipse object
	 * @param xPos the x position (top left corner of bounding rectangle)
	 * @param yPos the y position (top left corner of bounding rectangle)
	 * @param width the width of the ellipse (horizontal)
	 * @param height the height of the ellipse (vertical)
	 * @param color the color of the ellipse (Color class)
	 */
	public Ellipse(int xPos, int yPos, int width, int height, Color color) {
		this.setXPos(xPos);
		this.setYPos(yPos);
		this.width = width;
		this.height = height;
		this.setColor(color);
	}

	/**
	 * Paints the ellipse on the Graphics object g
	 */
	public void paint(Graphics g) {
		g.setColor(this.color);
		g.fillOval(getXPos(), getYPos(), width, height);
	}
}

package hw01.shape;

import java.awt.Color;
import java.awt.Graphics;

/**
 * 
 * @author charlielockyer
 * A concrete class representing a rectangle that can be painted on a graphics object
 */
public class Rectangle extends ASimpleShape {
	/**
	 * The width of the rectangle
	 */
	private int width;

	/**
	 * The height of the rectangle
	 */
	private int height;

	/**
	 * Constructs a rectangle object
	 * @param xPos the x position (top left corner)
	 * @param yPos the y position (top left corner)
	 * @param width the width of the rectangle (horizontal)
	 * @param height the height of the rectangle (vertical)
	 * @param color the color of the rectangle (Color class)
	 */
	public Rectangle(int xPos, int yPos, int width, int height, Color color) {
		this.setXPos(xPos);
		this.setYPos(yPos);
		this.width = width;
		this.height = height;
		this.setColor(color);
	}

	/**
	 * Paints the rectangle on the Graphics object g
	 */
	public void paint(Graphics g) {
		g.setColor(this.color);
		g.fillRect(getXPos(), getYPos(), width, height);
	}
}

package hw01.shape;

import java.awt.Color;
import java.awt.Graphics;

/**
 * 
 * @author charlielockyer
 * An abstract class describing an abstract simple shape on a 2D plane, like a screen
 * A simple shape has its own custom painting instructions, and is not composed of other shapes
 * Simple shapes are the most basic shapes and inherently have a color
 */
public abstract class ASimpleShape extends AShape {
	/**
	 * The color of the simple shape in the RGB color space; index 0 is R, 1 is G, and 2 is B
	 */
	protected Color color;

	/**
	 * Sets the color of the shape as written in AShape
	 */
	public void setColor(Color color) {
		this.color = color;
	}

	/**
	 * Paints the shape on the screen, abstract because each different shape is painted differently
	 */
	public abstract void paint(Graphics g);
}

